# Rate limiting and query complexity
class SecurityManager:
    def __init__(self):
        self.rate_limits = defaultdict(list)
        self.query_cache = {}
        self.max_depth = 5
        self.max_complexity = 100
        self.rate_limit_window = 60
        self.max_requests_per_window = 100
        
    def check_rate_limit(self, client_id: str) -> bool:
        current_time = time.time()
        self.rate_limits[client_id] = [
            t for t in self.rate_limits[client_id] 
            if current_time - t < self.rate_limit_window
        ]
        
        if len(self.rate_limits[client_id]) >= self.max_requests_per_window:
            return False
        
        self.rate_limits[client_id].append(current_time)
        return True
    
    def calculate_query_complexity(self, info) -> int:
        complexity = 0
        field_nodes = info.field_nodes
        
        for field_node in field_nodes:
            complexity += self._calculate_field_complexity(field_node, 1)
        
        return complexity
    
    def _calculate_field_complexity(self, field_node, depth: int) -> int:
        if depth > self.max_depth:
            raise Exception(f"Query depth exceeds maximum allowed depth of {self.max_depth}")
        
        complexity = 1
        
        if hasattr(field_node, 'selection_set') and field_node.selection_set:
            for selection in field_node.selection_set.selections:
                complexity += self._calculate_field_complexity(selection, depth + 1)
        
        return complexity
    
    def validate_query(self, info, client_id: str):
        if not self.check_rate_limit(client_id):
            raise Exception("Rate limit exceeded. Please try again later.")
        
        complexity = self.calculate_query_complexity(info)
        if complexity > self.max_complexity:
            raise Exception(f"Query complexity {complexity} exceeds maximum allowed complexity of {self.max_complexity}")

