# Input validation and sanitization
class InputValidator:
    ALLOWED_OPERATORS = ['=', '>', '<', '>=', '<=', 'LIKE', 'ILIKE', 'IN']
    ALLOWED_SORT_ORDERS = ['ASC', 'DESC']
    MAX_LIMIT = 1000
    
    @staticmethod
    def sanitize_field_name(field_name: str, allowed_fields: list) -> str:
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', field_name):
            raise ValueError(f"Invalid field name: {field_name}")
        
        if field_name not in allowed_fields:
            raise ValueError(f"Field {field_name} is not allowed for searching")
        
        return field_name
    
    @staticmethod
    def sanitize_operator(operator: str) -> str:
        operator = operator.upper()
        if operator not in InputValidator.ALLOWED_OPERATORS:
            raise ValueError(f"Operator {operator} is not allowed")
        return operator
    
    @staticmethod
    def sanitize_sort_order(order: str) -> str:
        order = order.upper()
        if order not in InputValidator.ALLOWED_SORT_ORDERS:
            raise ValueError(f"Sort order {order} is not allowed")
        return order
    
    @staticmethod
    def validate_limit(limit: int) -> int:
        if limit is None:
            return 100
        if limit < 1 or limit > InputValidator.MAX_LIMIT:
            raise ValueError(f"Limit must be between 1 and {InputValidator.MAX_LIMIT}")
        return limit
    
    @staticmethod
    def validate_offset(offset: int) -> int:
        if offset is None:
            return 0
        if offset < 0:
            raise ValueError("Offset must be non-negative")
        return offset

